import React from 'react';
import styles from './Experience.module.css';

const Experience = () => {
  const timeline = [
    {
      type: 'work',
      title: 'Senior Full-Stack Developer',
      company: 'TechCorp Solutions',
      period: '2023 - Present',
      description: 'Leading development of enterprise applications using React, Node.js, and AWS. Mentoring junior developers and implementing best practices.',
      technologies: ['React', 'TypeScript', 'Node.js', 'AWS', 'MongoDB']
    },
    {
      type: 'work',
      title: 'Frontend Developer',
      company: 'Digital Innovations',
      period: '2021 - 2023',
      description: 'Developed responsive web applications and collaborated with design teams to implement pixel-perfect UIs.',
      technologies: ['React', 'JavaScript', 'CSS3', 'Firebase']
    },
    {
      type: 'education',
      title: 'Bachelor of Computer Science',
      company: 'University of Technology',
      period: '2017 - 2021',
      description: 'Graduated with honors. Focus on software engineering, algorithms, and web technologies.',
      technologies: ['Java', 'Python', 'Database Design', 'Software Engineering']
    },
    {
      type: 'work',
      title: 'Junior Developer',
      company: 'StartUp Labs',
      period: '2020 - 2021',
      description: 'Built mobile applications using Flutter and contributed to backend API development.',
      technologies: ['Flutter', 'Dart', 'Express.js', 'PostgreSQL']
    }
  ];

  return (
    <section id="experience" className={styles.experience}>
      <div className={styles.container}>
        <div className={styles.sectionTitle}>
          <h2>Experience & Education</h2>
          <p>My journey in software development</p>
        </div>

        <div className={styles.timeline}>
          {timeline.map((item, index) => (
            <div key={index} className={`${styles.timelineItem} ${styles[item.type]}`}>
              <div className={styles.timelineMarker}>
                <div className={styles.markerIcon}>
                  {item.type === 'work' ? '💼' : '🎓'}
                </div>
              </div>
              <div className={styles.timelineContent}>
                <div className={styles.period}>{item.period}</div>
                <h3 className={styles.title}>{item.title}</h3>
                <div className={styles.company}>{item.company}</div>
                <p className={styles.description}>{item.description}</p>
                <div className={styles.technologies}>
                  {item.technologies.map((tech, techIndex) => (
                    <span key={techIndex} className={styles.tech}>{tech}</span>
                  ))}
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Experience;
